export const generateDeepAnalysis = async (
    title: string,
    content: string, // Full text or Summary
    apiKey?: string
): Promise<DeepAnalysisResult | null> => {
    const ai = getAIClient(apiKey);
    const prompt = `Act as an expert Academic Nephrologist. Perform a rigorous Methodological and Clinical Analysis of the following study.

    Target Structure (JSON):
    1. keyResults: Array of objects { group: "Intervention/Control", outcome: "Primary Outcome", pValue: "0.0x" }. Summarize quantitative data table.
    2. biasRisk: "Low", "Moderate", or "High".
    3. biasReason: Short explanation of bias assessment (e.g. "Open-label design", "Loss to follow-up").
    4. limitations: Array of strings listing methodological limitations.

    Study Title: ${title}
    Study Content: ${content.substring(0, 15000)} (Truncated if too long)`;

    try {
        const response = await fetchWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: prompt,
            config: { responseMimeType: "application/json" }
        }));
        return JSON.parse(cleanJson(response.text || '{}')) as DeepAnalysisResult;
    } catch (e) {
        console.error("Deep Analysis Failed", e);
        return null;
    }
};

export const chatWithArticle = async (
    history: ChatMessage[],
    newMessage: string,
    context: string, // Article full text or summary
    apiKey?: string
): Promise<string> => {
    const ai = getAIClient(apiKey);
    const systemPrompt = `You are an expert Nephrology Research Assistant. You are analyzing a specific scientific article.
    Context:
    ${context.substring(0, 20000)}...

    Instructions:
    1. Answer ONLY based on the provided text. If the text doesn't say, state "The article does not specify...".
    2. Be precise with data (doses, p-values, N).
    3. Keep answers concise and clinical.`;

    const chat = ai.chats.create({
        model: "gemini-3-flash-preview",
        config: { systemInstruction: systemPrompt }
    });

    const historyParts = history.map(h => ({
        role: h.role,
        parts: [{ text: h.content }]
    }));

    const chatSession = ai.chats.create({
        model: "gemini-3-flash-preview",
        config: { systemInstruction: systemPrompt },
        history: historyParts
    });

    try {
        const result = await chatSession.sendMessage({ message: newMessage });
        return result.text || "No response generated.";
    } catch (e) {
        console.error("Chat Failed", e);
        return "Error connecting to AI assistant.";
    }
};

export const generateModeratorComment = async (
    comments: Comment[],
    articleTitle: string,
    articleSummary: string,
    apiKey?: string
): Promise<string> => {
    const ai = getAIClient(apiKey);
    const threadContext = comments.map(c => `${c.user_name} said: ${c.content}`).join("\n");

    const prompt = `Act as a "Devil's Advocate" Scientific Moderator in a Journal Club.
    Your goal is to break confirmation bias and challenge weak arguments in the discussion thread politely but rigorously.

    Article: ${articleTitle}
    Summary: ${articleSummary}

    Current Discussion:
    ${threadContext}

    Instructions:
    1. Identify logical fallacies or overlooked limitations in the study that the users are ignoring.
    2. Ask a provocative scientific question to stimulate critical thinking.
    3. Be concise (max 2 sentences).
    4. Do NOT be rude. Be purely academic.

    Generate the moderator comment.`;

    try {
        const response = await fetchWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt
        }));
        return response.text || "Interesting points. However, have we considered the limitations of the sample size in this cohort?";
    } catch (e) {
        return "Critical analysis required. Please consider potential confounders.";
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../services/supabaseClient';
import { Article, Comment, ReactionType } from '../types';
import { Send, User, MessageCircle, AlertTriangle, Lightbulb, TrendingDown, ShieldCheck, Loader2, Bot } from 'lucide-react';
import { generateModeratorComment } from '../services/geminiService';
import { motion, AnimatePresence } from 'framer-motion';

interface SocialJournalClubProps {
  article: Article;
  isDarkMode: boolean;
  geminiApiKey?: string;
}

const REACTION_CONFIG: Record<ReactionType, { icon: React.ElementType, label: string, color: string }> = {
    'solid': { icon: ShieldCheck, label: 'Sólido', color: 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20' },
    'biased': { icon: AlertTriangle, label: 'Sesgado', color: 'text-red-500 bg-red-500/10 border-red-500/20' },
    'novel': { icon: Lightbulb, label: 'Novedoso', color: 'text-purple-500 bg-purple-500/10 border-purple-500/20' },
    'limited': { icon: TrendingDown, label: 'Limitado', color: 'text-slate-500 bg-slate-500/10 border-slate-500/20' },
};

const SocialJournalClub: React.FC<SocialJournalClubProps> = ({ article, isDarkMode, geminiApiKey }) => {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [user, setUser] = useState<any>(null); // Mock auth for MVP if Supabase auth not fully implemented
  const [moderatorThinking, setModeratorThinking] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // MOCK AUTH (Replace with proper auth context in full prod)
  // We'll simulate a random user for now if not logged in to Supabase
  useEffect(() => {
      const initAuth = async () => {
          const { data } = await supabase.auth.getSession();
          if (data.session) {
              setUser(data.session.user);
          } else {
              // Create a temp session or prompt login. 
              // For this demo, we'll assume a "Guest Fellow"
              setUser({ id: 'guest-' + Math.random(), email: 'guest@nephro.club', user_metadata: { full_name: 'Guest Fellow' } });
          }
      };
      initAuth();
  }, []);

  // Fetch Comments & Subscribe
  useEffect(() => {
    const fetchComments = async () => {
        setLoading(true);
        const { data, error } = await supabase
            .from('comments')
            .select('*')
            .eq('article_id', article.id)
            .order('created_at', { ascending: true });

        if (!error && data) {
            setComments(data as Comment[]);
        }
        setLoading(false);
    };

    fetchComments();

    const channel = supabase
      .channel('public:comments')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'comments', filter: `article_id=eq.${article.id}` }, (payload) => {
          setComments(prev => [...prev, payload.new as Comment]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [article.id]);

  useEffect(() => {
      if (scrollRef.current) {
          scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
  }, [comments]);

  const handlePostComment = async () => {
      if (!newComment.trim() || !user) return;
      setSending(true);

      const payload = {
          article_id: article.id,
          user_id: user.id,
          user_name: user.user_metadata?.full_name || 'Anonymous Dr.',
          user_specialty: 'Nephrology',
          content: newComment,
      };

      const { error } = await supabase.from('comments').insert([payload]);

      if (error) {
          console.error("Error posting:", error);
          // Fallback for demo if SQL table missing: Local Update
          const mockComment: Comment = { 
              id: Date.now().toString(), 
              created_at: new Date().toISOString(), 
              ...payload 
          } as Comment;
          setComments(prev => [...prev, mockComment]);
      } else {
          setNewComment('');
      }
      setSending(false);
  };

  const handleTriggerModerator = async () => {
      setModeratorThinking(true);
      const modText = await generateModeratorComment(comments, article.title, article.summary, geminiApiKey);

      const modPayload = {
          article_id: article.id,
          user_id: 'ai-moderator',
          user_name: 'AI Moderator (Devil\'s Advocate)',
          user_specialty: 'Evidence Based AI',
          content: modText,
          is_ai_moderator: true
      };

      await supabase.from('comments').insert([modPayload]);
      // Also local fallback if db fails
      setComments(prev => [...prev, { id: Date.now().toString(), created_at: new Date().toISOString(), ...modPayload } as Comment]);

      setModeratorThinking(false);
  };

  return (
    <div className={`flex flex-col h-full ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'}`}>

        {/* Header / Info */}
        <div className={`p-4 border-b shrink-0 ${isDarkMode ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>
            <div className="flex items-center justify-between mb-2">
                <h3 className={`font-black uppercase tracking-widest text-xs flex items-center gap-2 ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>
                    <MessageCircle size={14} className="text-blue-500" />
                    Social Journal Club
                </h3>
                <span className="text-[10px] opacity-50 font-bold">LIVE EBD</span>
            </div>
            <p className="text-[10px] opacity-60 leading-tight">
                Discusión basada en evidencia. Usa las reacciones científicas para evaluar la metodología.
            </p>
        </div>

        {/* Comments Feed */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
            {loading ? (
                <div className="flex justify-center py-10"><Loader2 className="animate-spin text-slate-400" /></div>
            ) : comments.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                    <MessageCircle size={48} className="mx-auto mb-2" />
                    <p className="text-xs font-bold uppercase">Sé el primero en opinar</p>
                </div>
            ) : (
                comments.map((comment) => (
                    <motion.div 
                        initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                        key={comment.id} 
                        className={`p-3 rounded-2xl border relative ${
                            comment.is_ai_moderator 
                                ? (isDarkMode ? 'bg-purple-900/10 border-purple-500/30' : 'bg-purple-50 border-purple-200') 
                                : (isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200')
                        }`}
                    >
                        <div className="flex items-center gap-2 mb-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center ${comment.is_ai_moderator ? 'bg-purple-500 text-white' : 'bg-blue-600 text-white'}`}>
                                {comment.is_ai_moderator ? <Bot size={14} /> : <User size={12} />}
                            </div>
                            <div>
                                <span className={`text-xs font-bold block leading-none ${isDarkMode ? 'text-slate-200' : 'text-slate-900'}`}>
                                    {comment.user_name}
                                </span>
                                <span className="text-[9px] opacity-50">{comment.user_specialty} • {new Date(comment.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                            </div>
                        </div>
                        <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>
                            {comment.content}
                        </p>
                    </motion.div>
                ))
            )}

            {moderatorThinking && (
                <div className="flex gap-2 items-center text-xs font-bold text-purple-500 animate-pulse">
                    <Bot size={14} /> AI Moderator analyzing bias...
                </div>
            )}
        </div>

        {/* Reaction Bar (Sticky Bottom of Feed) */}
        <div className={`p-2 flex justify-center gap-2 border-t ${isDarkMode ? 'border-slate-800 bg-slate-900/50' : 'border-slate-200 bg-slate-50/50'}`}>
            {(Object.keys(REACTION_CONFIG) as ReactionType[]).map(type => {
                const conf = REACTION_CONFIG[type];
                return (
                    <button key={type} className={`flex flex-col items-center gap-1 p-2 rounded-xl border transition-all active:scale-95 ${conf.color} hover:brightness-110`}>
                        <conf.icon size={16} />
                        <span className="text-[8px] font-black uppercase">{conf.label}</span>
                    </button>
                )
            })}
        </div>

        {/* Input Area */}
        <div className={`p-3 border-t flex flex-col gap-2 ${isDarkMode ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>
            {comments.length > 2 && !moderatorThinking && (
                <button 
                    onClick={handleTriggerModerator}
                    className={`w-full py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-colors ${isDarkMode ? 'bg-purple-900/20 text-purple-400 hover:bg-purple-900/30' : 'bg-purple-100 text-purple-600 hover:bg-purple-200'}`}
                >
                    <Bot size={12} /> Invocar Moderador (Devil's Advocate)
                </button>
            )}
            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={newComment}
                    onChange={e => setNewComment(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handlePostComment()}
                    placeholder="Añade tu crítica o comentario..."
                    className={`flex-1 p-3 rounded-xl text-sm outline-none ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-100 text-slate-900 placeholder-slate-400'}`}
                />
                <button 
                    onClick={handlePostComment}
                    disabled={sending || !newComment.trim()}
                    className="p-3 rounded-xl bg-blue-600 text-white shadow-lg active:scale-95 disabled:opacity-50"
                >
                    {sending ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
                </button>
            </div>
        </div>
    </div>
  );
};

