                            {tab.id === 'pdf' && article.fullTextContent && <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 ml-1" />}
                        </button>
                    ))}
                </div>

                {/* External Link Button (System Browser) */}
                <button 
