export const getConsensusStats = (notes: CommunityNote[]): Record<ReactionType, number> => {
    const total = notes.length;
    if (total === 0) return { solid: 0, biased: 0, practice_change: 0, educational: 0 };

    const counts: Record<ReactionType, number> = { solid: 0, biased: 0, practice_change: 0, educational: 0 };

    notes.forEach(n => {
        if (n.reaction) counts[n.reaction] = (counts[n.reaction] || 0) + 1;
    });

    // Normalize to percentages
    const result: any = {};
    let totalReactions = 0;
    Object.keys(counts).forEach(k => totalReactions += counts[k as ReactionType]);

    if (totalReactions === 0) return { solid: 0, biased: 0, practice_change: 0, educational: 0 };

    (Object.keys(counts) as ReactionType[]).forEach(k => {
        result[k] = Math.round((counts[k] / totalReactions) * 100);
    });

    return result;
};

export const generateDevilAdvocateComment = (article: Article): string => {
    const critiques = [
        `Aunque el resultado primario es positivo, el intervalo de confianza (IC 95%) es muy amplio. ¿Realmente es robusto?`,
        `Nótese que excluyeron pacientes con GFR < 20 ml/min. La aplicabilidad en estadio 5 es cuestionable.`,
        `El diseño es abierto (open-label). Existe un riesgo considerable de sesgo de realización.`,
        `¿Han considerado que el estudio fue financiado por el fabricante? Falta análisis independiente.`,
        `El tamaño de muestra (N=${article.summary.match(/n\s*[=:]\s*(\d+)/i)?.[1] || '...'}) parece insuficiente para los outcomes secundarios.`,
        `El valor P es marginal (p=0.049). En mi opinión, requiere validación externa antes de cambiar práctica.`
    ];
    return critiques[Math.floor(Math.random() * critiques.length)];
};

