    const chat = ai.chats.create({
        model: "gemini-3-flash-preview",
        config: { systemInstruction: systemPrompt }
    });

    const historyParts = history.map(h => ({
        role: h.role,
        parts: [{ text: h.content }]
    }));

    const chatSession = ai.chats.create({
        model: "gemini-3-flash-preview",
        config: { systemInstruction: systemPrompt },
        history: historyParts
