export type Topic = string;
export type Language = 'original' | 'es';

export type ArticleCategory = 
  | 'Research' 
  | 'News' 
  | 'Case Study' 
  | 'Publication' 
  | 'Clinical Trial' 
  | 'Manual'
  | 'Guideline'      // Green
  | 'Retraction'     // Red
  | 'Meta-Analysis'  // Purple
  | 'Review'         // Amber
  | 'Cohort';        // Blue/Slate

export interface Article {
  id: string;
  title: string;
  summary: string;
  source: string;
  authors?: string;
  url: string;
  date: string;
  category: ArticleCategory;
  relevanceScore: number;
  topic?: string;
  updates?: Article[];
  isFree?: boolean; // New field for Open Access status
  note?: string; // Personal user note
  imageUrl?: string; // URL for article thumbnail or figure
  visualAbstract?: string; // ASCII/Markdown visual abstract

  // New Clinical TL;DR Feature
  clinicalTldr?: {
    change: string;
    population: string;
  };

  // Associated Publications (e.g., for Clinical Trials)
  associatedPublications?: string[];

  // New Study Features
  readingStatus?: 'unread' | 'in_progress' | 'completed';
  highlights?: string[]; // Array of selected text snippets
  lastReadAt?: number; // Timestamp for Spaced Repetition

  // PDF Ecosystem Features
  localPdfData?: string; // Base64 encoded PDF string
  fullTextContent?: string; // Semantic text extracted from PDF for AI
}

export interface ResearchUpdate {
  articles: Article[];
  summary: string;
  searchMode?: SearchMode; // Track which mode generated this result
  language?: Language;     // Track content language
}

export interface HistorySnapshot {
  id: string;
  date: string; // ISO String of when the fetch happened
  timestamp: number;
  topic: string;
  query?: string;
  sessionQueries?: string[]; // New: List of queries grouped in this session
  summary: string;
  articles: Article[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export interface Comment {
  id: string;
  user_name: string;
  content: string;
  timestamp: number;
}

export interface DeepAnalysisResult {
  keyResults: { group: string; outcome: string; pValue: string }[];
  biasRisk: 'Low' | 'Moderate' | 'High';
  biasReason: string;
  limitations: string[];
}

// --- SOCIAL JOURNAL CLUB ARCHITECTURE ---

export type ReactionType = 'solid' | 'biased' | 'practice_change' | 'educational';

export interface SocialProfile {
  id: string;          // 'me', 'ai-mod', 'u1', etc.
  name: string;        // Nombre visible (ej. "Dr. Demo")
  specialty: string;   // Ej. "Nephrology"
  institution: string; // Ej. "Hospital Clínico"
  badges?: string[];   // Array de strings: ['Top Critic', 'Expert', 'Moderator']
  isBot?: boolean;     // Visual helper
}

export interface CommunityNote {
  id: string;
  articleId: string;       // ID del paper vinculado
  userId: string;
  userProfile: SocialProfile;
  text: string;            // Contenido del comentario
  timestamp: number;
  reaction?: ReactionType; // Voto científico
  anchoredText?: string;   // (Opcional) Texto citado del paper
  isAudio?: boolean;       // (Opcional) Si es nota de voz
  audioDuration?: string;  // Ej. "0:45"
  likes: number;
  isAiModerator?: boolean; // Flag crítico para estilo del Bot
  replies?: CommunityNote[]; // Recursividad: Respuestas anidadas
}

export interface DebateTopic {
  id: string;
  title: string;           // Ej. "SGLT2i en Trasplante"
  category: string;        // Ej. "CKD"
  participantsCount: number;
  controversyLevel: 'High' | 'Medium' | 'Low'; // Determina color de UI (Rojo/Ámbar/Verde)
  consensusSplit: { 
      pro: number;         // Porcentaje (0-100)
      con: number;         // Porcentaje (0-100)
  }; 
  linkedArticle: Article; // Paper base obligatorio
  isUserProposed?: boolean; // Si fue creado por el usuario en esta sesión
  updatedAt: number;
}

export type RetentionPeriod = '7' | '30' | '90' | 'forever';

// Updated to 4-level scale (A-AAAA)
export type TextSize = 'sm' | 'base' | 'lg' | 'xl';
export type SearchMode = 'ai' | 'standard';
export type DataSource = 'pubmed' | 'openalex' | 'europepmc' | 'semanticscholar' | 'clinicaltrials' | 'core' | 'doaj' | 'elsevier' | 'lilacs';
export type UiLanguage = 'es' | 'en';
export type AIProvider = 'gemini' | 'groq';
export type FontStyle = 'sans' | 'serif' | 'modern';

