import { generateModeratorComment, generatePodcastAudio } from '../services/geminiService';
import { PROFILE_ME, PROFILE_AI, getConsensusStats, generateDevilAdvocateComment } from '../services/socialService';
import { motion, AnimatePresence } from 'framer-motion';

interface SocialJournalClubProps {
  article: Article;
  isDarkMode: boolean;
  geminiApiKey?: string;
}

const REACTION_CONFIG: Record<ReactionType, { icon: React.ElementType, label: string, color: string }> = {
    'solid': { icon: ShieldCheck, label: 'Sólido', color: 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20' },
    'biased': { icon: AlertTriangle, label: 'Sesgado', color: 'text-amber-500 bg-amber-500/10 border-amber-500/20' },
    'practice_change': { icon: Lightbulb, label: 'Impacto', color: 'text-blue-500 bg-blue-500/10 border-blue-500/20' },
    'educational': { icon: TrendingDown, label: 'Educativo', color: 'text-purple-500 bg-purple-500/10 border-purple-500/20' },
};

const SMART_CHIPS = [
    { label: "Criticar N", text: "El tamaño de la muestra parece insuficiente para obtener potencia estadística en los outcomes secundarios." },
    { label: "Sesgo", text: "Existe un riesgo potencial de sesgo debido al diseño abierto del estudio." },
    { label: "Citar P", text: "El valor P es marginal, lo que sugiere precaución en la interpretación." },
    { label: "Generalizar", text: "¿Son estos resultados aplicables a nuestra población local con comorbilidades?" }
];

const SocialJournalClub: React.FC<SocialJournalClubProps> = ({ article, isDarkMode, geminiApiKey }) => {
  const [notes, setNotes] = useState<CommunityNote[]>([]);
  const [newNoteText, setNewNoteText] = useState('');
  const [selectedReaction, setSelectedReaction] = useState<ReactionType | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioLoading, setAudioLoading] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Consensus Stats
  const consensus = getConsensusStats(notes);

  // 1. AUTO TRIGGER: Devil's Advocate
  useEffect(() => {
      let timeout: ReturnType<typeof setTimeout>;
      // Trigger if few notes exist to stimulate debate
      if (notes.length < 5) {
          timeout = setTimeout(() => {
              const aiText = generateDevilAdvocateComment(article);
              const aiNote: CommunityNote = {
                  id: `ai-${Date.now()}`,
                  articleId: article.id,
                  userId: PROFILE_AI.id,
                  userProfile: PROFILE_AI,
                  text: aiText,
                  timestamp: Date.now(),
                  reaction: 'biased', // AI usually plays skeptic
                  likes: 0,
                  isAiModerator: true
              };
              setNotes(prev => {
                  // Prevent duplicate if already added
                  if (prev.some(n => n.isAiModerator)) return prev;
                  if (navigator.vibrate) navigator.vibrate(50);
                  return [...prev, aiNote];
              });
          }, 5000); // 5 seconds delay
      }
      return () => clearTimeout(timeout);
  }, [article, notes.length]);

  // Scroll to bottom on new note
  useEffect(() => {
      if (scrollRef.current) {
          scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
  }, [notes]);

  const handlePostNote = () => {
      if (!newNoteText.trim()) return;

      const note: CommunityNote = {
          id: `u-${Date.now()}`,
          articleId: article.id,
          userId: PROFILE_ME.id,
          userProfile: PROFILE_ME,
          text: newNoteText,
          timestamp: Date.now(),
          reaction: selectedReaction,
          likes: 0
      };

      setNotes(prev => [...prev, note]);
      setNewNoteText('');
      setSelectedReaction(undefined);
  };

  const handleChipClick = (text: string) => {
      setNewNoteText(text);
  };

  const handlePodcastMode = async () => {
      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
          return;
      }

      if (notes.length === 0) return;

      setAudioLoading(true);
      // Construct a script for the TTS
      const script = "Resumen del debate actual: " + notes.slice(-5).map(n => `${n.userProfile.name} dice: ${n.text}`).join(". ");

      try {
          const base64Audio = await generatePodcastAudio(script, geminiApiKey);
          if (base64Audio) {
              const audioSrc = `data:audio/wav;base64,${base64Audio}`;
              if (!audioRef.current) audioRef.current = new Audio();
              audioRef.current.src = audioSrc;
              audioRef.current.play();
              setIsPlaying(true);
              audioRef.current.onended = () => setIsPlaying(false);
          }
      } catch (e) {
          console.error("Podcast failed", e);
      } finally {
          setAudioLoading(false);
      }
  };

  return (
    <div className={`flex flex-col h-full ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'}`}>

        {/* Header & Consensus Bar */}
        <div className={`p-4 border-b shrink-0 ${isDarkMode ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>
            <div className="flex items-center justify-between mb-3">
                <h3 className="font-black uppercase tracking-widest text-xs text-amber-500">Social Journal Club (Simulado)</h3>
                <button 
                    onClick={handlePodcastMode}
                    disabled={audioLoading}
                    className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-[9px] font-bold uppercase transition-all ${isPlaying ? 'bg-red-500 text-white animate-pulse' : (isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-slate-100 text-slate-600')}`}
                >
                    {audioLoading ? <Loader2 size={10} className="animate-spin" /> : (isPlaying ? <Square size={10} fill="currentColor" /> : <Play size={10} fill="currentColor" />)}
                    {isPlaying ? 'Stop' : 'Escuchar'}
                </button>
            </div>

            {/* Scientific Thermometer */}
            <div className="flex h-2 rounded-full overflow-hidden w-full bg-slate-200 dark:bg-slate-800">
                <div style={{ width: `${consensus.solid}%` }} className="bg-emerald-500 transition-all duration-500" title="Sólido" />
                <div style={{ width: `${consensus.biased}%` }} className="bg-amber-500 transition-all duration-500" title="Sesgado" />
                <div style={{ width: `${consensus.practice_change}%` }} className="bg-blue-500 transition-all duration-500" title="Impacto" />
                <div style={{ width: `${consensus.educational}%` }} className="bg-purple-500 transition-all duration-500" title="Educativo" />
            </div>
            <div className="flex justify-between mt-1 text-[8px] font-bold uppercase opacity-40">
                <span>Evidencia</span>
                <span>Consenso</span>
            </div>
        </div>

        {/* Comments Feed */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
            {notes.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                    <Bot size={48} className="mx-auto mb-2 text-slate-400" />
                    <p className="text-xs font-bold uppercase">Esperando análisis...</p>
                </div>
            ) : (
                notes.map((note) => (
                    <motion.div 
                        initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                        key={note.id} 
                        className={`p-3 rounded-2xl border relative ${
                            note.isAiModerator 
                                ? (isDarkMode ? 'bg-red-900/10 border-red-500/20' : 'bg-red-50 border-red-100') 
                                : (isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200')
                        }`}
                    >
                        <div className="flex items-center gap-2 mb-2">
                            <div className={`w-6 h-6 rounded-full flex items-center justify-center ${note.isAiModerator ? 'bg-red-500 text-white' : 'bg-blue-600 text-white'}`}>
                                {note.isAiModerator ? <Bot size={14} /> : note.userProfile.name.charAt(0)}
                            </div>
                            <div>
                                <span className={`text-xs font-bold block leading-none ${isDarkMode ? 'text-slate-200' : 'text-slate-900'}`}>
                                    {note.userProfile.name}
                                </span>
                                <span className="text-[9px] opacity-50">{note.userProfile.specialty}</span>
                            </div>
                            {note.reaction && (
                                <div className={`ml-auto px-1.5 py-0.5 rounded text-[8px] font-black uppercase ${REACTION_CONFIG[note.reaction].color}`}>
                                    {REACTION_CONFIG[note.reaction].label}
                                </div>
                            )}
                        </div>
                        <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>
                            {note.text}
                        </p>
                    </motion.div>
                ))
            )}
        </div>

        {/* Smart Chips & Input */}
        <div className={`p-3 border-t flex flex-col gap-2 ${isDarkMode ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>

            {/* Smart Chips Scroll */}
            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                {SMART_CHIPS.map((chip, idx) => (
                    <button 
                        key={idx} 
                        onClick={() => handleChipClick(chip.text)}
                        className={`whitespace-nowrap px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase tracking-wide border transition-all active:scale-95 ${isDarkMode ? 'border-slate-700 bg-slate-800 text-slate-300 hover:bg-slate-700' : 'border-slate-200 bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
                    >
                        {chip.label}
                    </button>
                ))}
            </div>

            {/* Reaction Selector (Mini) */}
            <div className="flex justify-between gap-1 mb-1">
                {(Object.keys(REACTION_CONFIG) as ReactionType[]).map(type => {
                    const conf = REACTION_CONFIG[type];
                    const isSelected = selectedReaction === type;
                    return (
                        <button 
                            key={type} 
                            onClick={() => setSelectedReaction(isSelected ? undefined : type)}
                            className={`flex-1 flex justify-center items-center p-1.5 rounded-lg border transition-all ${isSelected ? conf.color + ' ring-1 ring-offset-1 ring-offset-transparent ring-current' : (isDarkMode ? 'border-slate-800 text-slate-500 opacity-50' : 'border-slate-200 text-slate-400')}`}
                        >
                            <conf.icon size={14} />
                        </button>
                    )
                })}
            </div>

            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={newNoteText}
                    onChange={e => setNewNoteText(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handlePostNote()}
                    placeholder="Debate clínico..."
                    className={`flex-1 p-3 rounded-xl text-sm outline-none ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-100 text-slate-900 placeholder-slate-400'}`}
                />
                <button 
                    onClick={handlePostNote}
                    disabled={!newNoteText.trim()}
                    className="p-3 rounded-xl bg-blue-600 text-white shadow-lg active:scale-95 disabled:opacity-50"
                >
                    <Send size={18} />
                </button>
            </div>
        </div>
    </div>
  );
};

export default SocialJournalClub;
